+        stage.setWidth(200);
+        stage.setHeight(200);
+
+        stage.show();
+        intSpinner.requestFocus();
+        tk.firePulse();
+
+        var event = new KeyEvent(KeyEvent.KEY_PRESSED, "", "", KeyCode.Q, false, false, false, true);
